import React, { useState } from 'react';
import axios from 'axios';
import { jwtDecode } from 'jwt-decode';

function LoginPage() {
  const [isRegister, setIsRegister] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [role, setRole] = useState('staff');

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post(`${process.env.REACT_APP_API_URL}/api/auth/login`, {
        email,
        password,
      });
      const decoded = jwtDecode(res.data.token);
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('role', decoded.role);
      window.location.href = '/dashboard';
    } catch (err) {
      alert('Đăng nhập thất bại: Lỗi kết nối hoặc sai thông tin');
    }
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    try {
      await axios.post(`${process.env.REACT_APP_API_URL}/api/auth/register`, {
        email,
        password,
        role,
      });
      alert('✅ Đăng ký thành công! Bạn có thể đăng nhập.');
      setIsRegister(false);
    } catch (err) {
      alert('❌ Đăng ký thất bại. Có thể email đã tồn tại.');
    }
  };

  return (
    <div>
      <h2>{isRegister ? 'Đăng ký tài khoản' : 'Đăng nhập'}</h2>

      <form onSubmit={isRegister ? handleRegister : handleLogin}>
        <input
          type="email"
          placeholder="Email"
          value={email}
          onChange={e => setEmail(e.target.value)}
          required
        /><br />
        <input
          type="password"
          placeholder="Mật khẩu"
          value={password}
          onChange={e => setPassword(e.target.value)}
          required
        /><br />

        {isRegister && (
          <>
            <select value={role} onChange={e => setRole(e.target.value)}>
              <option value="staff">Nhân viên</option>
              <option value="admin">Quản trị viên</option>
            </select><br />
          </>
        )}

        <button type="submit">{isRegister ? 'Đăng ký' : 'Đăng nhập'}</button>
      </form>

      <p style={{ marginTop: '10px' }}>
        {isRegister ? (
          <>Đã có tài khoản? <button onClick={() => setIsRegister(false)}>Đăng nhập</button></>
        ) : (
          <>Chưa có tài khoản? <button onClick={() => setIsRegister(true)}>Đăng ký</button></>
        )}
      </p>
    </div>
  );
}

export default LoginPage;
